// ============================================
// LÓGICA DE VERIFICAÇÃO DE ACESSO
// ============================================

const userId = $('2. Extrair userId e appId').item.json.user_id;
const appId = $('2. Extrair userId e appId').item.json.app_id;

// Obter dados das análises
const comprasData = $('6. Analisar Compras').item.json;
const trialsData = $('7. Analisar Trials').item.json;

// Parsear JSON
const compras = JSON.parse(comprasData.purchases_data || '[]');
const trials = JSON.parse(trialsData.trials_data || '[]');

console.log('📊 Total compras:', compras.length);
console.log('📊 Total trials:', trials.length);

// Variáveis de resultado
let hasAccess = false;
let accessType = null;
let expiresAt = null;
let reason = null;

// ============================================
// 1. VERIFICAR LIFETIME (Prioridade Máxima)
// ============================================
for (const compra of compras) {
  if (compra.purchase_type === 'LIFETIME') {
    hasAccess = true;
    accessType = 'LIFETIME';
    reason = 'Compra LIFETIME encontrada';
    console.log('✅ LIFETIME encontrado!');
    break;
  }
}

// ============================================
// 2. VERIFICAR ASSINATURAS (MONTHLY/ANNUAL)
// ============================================
if (!hasAccess) {
  const now = new Date();

  for (const compra of compras) {
    if (['MONTHLY', 'ANNUAL'].includes(compra.purchase_type)) {
      const expDate = compra.expires_at ? new Date(compra.expires_at) : null;

      if (expDate && expDate > now) {
        hasAccess = true;
        accessType = compra.purchase_type;
        expiresAt = compra.expires_at;
        reason = `Assinatura ${compra.purchase_type} ativa até ${expDate.toLocaleDateString()}`;
        console.log(`✅ Assinatura ${compra.purchase_type} válida!`);
        break;
      } else {
        console.log(`⚠️ Assinatura ${compra.purchase_type} expirada`);
      }
    }
  }
}

// ============================================
// 3. VERIFICAR TRIAL
// ============================================
if (!hasAccess && trials.length > 0) {
  const trial = trials[0]; // Primeiro trial ativo
  hasAccess = true;
  accessType = 'TRIAL';
  expiresAt = trial.expires_at;
  const expDate = new Date(trial.expires_at);
  reason = `Trial ativo até ${expDate.toLocaleDateString()}`;
  console.log('✅ Trial ativo encontrado!');
}

// ============================================
// 4. SEM ACESSO
// ============================================
if (!hasAccess) {
  reason = 'Nenhuma compra, assinatura ou trial ativo encontrado';
  console.log('❌ Sem acesso');
}

// ============================================
// RETORNO
// ============================================
return {
  userId,
  appId,
  hasAccess,
  accessType,
  expiresAt,
  reason,
  debug: {
    totalCompras: compras.length,
    totalTrials: trials.length,
    comprasTypes: compras.map(c => c.purchase_type),
    timestamp: new Date().toISOString()
  }
};
